def get_cell_umi_read_string(read_id, sep):
    """
    Extract UMI and cell barcode from a read ID string using the given separator.
    Returns (umi_bytes, cb_bytes) after encoding to UTF-8.
    Raises ValueError if the read_id does not contain valid barcode and UMI.
    """
    parts = read_id.split(sep)
    if len(parts) < 2:
        raise ValueError(
            'Could not extract UMI or CB from the read ID, pleasecheck UMI and CB are encoded in the read name:%s'
            % read_id
        )

    last_two = parts[-2:]
    # Case where last two fields are exactly 'CB' and 'UMI'
    if last_two == ['CB', 'UMI']:
        return (b'UMI', b'CB')

    # Look for exact 'CB' and 'UMI' fields and use following fields
    cb_idx = None
    umi_idx = None
    for i, field in enumerate(parts):
        if field == 'CB':
            cb_idx = i
        if field == 'UMI':
            umi_idx = i
    if cb_idx is not None and umi_idx is not None and cb_idx < umi_idx:
        if cb_idx + 1 < len(parts) and umi_idx + 1 < len(parts):
            cb_val = parts[cb_idx + 1]
            umi_val = parts[umi_idx + 1]
            return (umi_val.encode('utf-8'), cb_val.encode('utf-8'))

    # Fallback: take last two fields, then within each take the part after the last underscore
    def last_after_underscore(s):
        us = s.split('_')
        return us[-1] if us else ''

    cb_raw = parts[-2]
    umi_raw = parts[-1]
    cb_val = last_after_underscore(cb_raw)
    umi_val = last_after_underscore(umi_raw)

    # Validate that extracted values look reasonable
    if not ((cb_val == '' or cb_val.startswith('CB')) and (umi_val == '' or umi_val.startswith('UMI'))):
        raise ValueError(
            'Could not extract UMI or CB from the read ID, pleasecheck UMI and CB are encoded in the read name:%s'
            % read_id
        )

    return (umi_val.encode('utf-8'), cb_val.encode('utf-8'))


